"use strict";

// Aula: O que é JSON?
// JSON (JavaScript Object Notation) é um formato de dados leve e fácil de ler/escrever.
// Usado para troca de dados entre sistemas, especialmente em APIs.
// Exemplo de um objeto em JSON:
var pessoaJSON = '{"nome": "João", "idade": 30, "profissao": "Desenvolvedor"}';
console.log('Texto JSON:', pessoaJSON); // Documentação:
// - JSON é um texto estruturado, parecido com objetos JavaScript.
// - Chaves e valores são separados por vírgula.
// - Usado para enviar e receber dados em aplicações web.